// BankingServiceImpl.java
package com.banking.service;

import javax.jws.WebService;
import javax.jws.WebMethod;
import javax.jws.WebParam;
import java.math.BigDecimal;
import java.util.UUID;
import java.util.concurrent.ConcurrentHashMap;
import java.util.Map;

@WebService(
    serviceName = "BankingService",
    portName = "BankingServicePort",
    targetNamespace = "http://banking.com/service",
    endpointInterface = "com.banking.service.BankingService"
)
public class BankingServiceImpl implements BankingService {
    
    private static Map<String, BigDecimal> accounts = new ConcurrentHashMap<>();
    
    static {
        accounts.put("ACC001", new BigDecimal("10000.00"));
        accounts.put("ACC002", new BigDecimal("5000.00"));
        accounts.put("ACC003", new BigDecimal("15000.00"));
    }
    
    @Override
    @WebMethod
    public TransactionResponse transferFunds(
        @WebParam(name = "fromAccount") String fromAccount,
        @WebParam(name = "toAccount") String toAccount,
        @WebParam(name = "amount") BigDecimal amount,
        @WebParam(name = "currency") String currency
    ) {
        String transactionId = UUID.randomUUID().toString();
        
        if (!accounts.containsKey(fromAccount)) {
            return new TransactionResponse(transactionId, "FAILED", "Source account not found");
        }
        
        if (!accounts.containsKey(toAccount)) {
            return new TransactionResponse(transactionId, "FAILED", "Destination account not found");
        }
        
        BigDecimal fromBalance = accounts.get(fromAccount);
        if (fromBalance.compareTo(amount) < 0) {
            return new TransactionResponse(transactionId, "FAILED", "Insufficient funds");
        }
        
        accounts.put(fromAccount, fromBalance.subtract(amount));
        accounts.put(toAccount, accounts.get(toAccount).add(amount));
        
        return new TransactionResponse(transactionId, "SUCCESS", "Transfer completed successfully");
    }
    
    @Override
    @WebMethod
    public BalanceResponse getBalance(@WebParam(name = "accountNumber") String accountNumber) {
        if (!accounts.containsKey(accountNumber)) {
            return new BalanceResponse(accountNumber, BigDecimal.ZERO, "USD", "FAILED");
        }
        
        return new BalanceResponse(accountNumber, accounts.get(accountNumber), "USD", "SUCCESS");
    }
    
    @Override
    @WebMethod
    public TransactionResponse depositFunds(
        @WebParam(name = "accountNumber") String accountNumber,
        @WebParam(name = "amount") BigDecimal amount,
        @WebParam(name = "currency") String currency
    ) {
        String transactionId = UUID.randomUUID().toString();
        
        if (!accounts.containsKey(accountNumber)) {
            return new TransactionResponse(transactionId, "FAILED", "Account not found");
        }
        
        accounts.put(accountNumber, accounts.get(accountNumber).add(amount));
        return new TransactionResponse(transactionId, "SUCCESS", "Deposit completed successfully");
    }
    
    @Override
    @WebMethod
    public TransactionResponse withdrawFunds(
        @WebParam(name = "accountNumber") String accountNumber,
        @WebParam(name = "amount") BigDecimal amount,
        @WebParam(name = "currency") String currency
    ) {
        String transactionId = UUID.randomUUID().toString();
        
        if (!accounts.containsKey(accountNumber)) {
            return new TransactionResponse(transactionId, "FAILED", "Account not found");
        }
        
        BigDecimal balance = accounts.get(accountNumber);
        if (balance.compareTo(amount) < 0) {
            return new TransactionResponse(transactionId, "FAILED", "Insufficient funds");
        }
        
        accounts.put(accountNumber, balance.subtract(amount));
        return new TransactionResponse(transactionId, "SUCCESS", "Withdrawal completed successfully");
    }
}


