package com.banking.security;

import org.apache.cxf.binding.soap.SoapMessage;
import org.apache.cxf.binding.soap.interceptor.AbstractSoapInterceptor;
import org.apache.cxf.interceptor.Fault;
import org.apache.cxf.phase.Phase;
import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;

import javax.xml.crypto.*;
import javax.xml.crypto.dsig.*;
import javax.xml.crypto.dsig.dom.DOMValidateContext;
import javax.xml.crypto.dsig.keyinfo.KeyInfo;
import javax.xml.crypto.dsig.keyinfo.KeyValue;
import javax.xml.crypto.dsig.keyinfo.X509Data;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import java.io.InputStream;
import java.security.Key;
import java.security.PublicKey;
import java.security.cert.X509Certificate;
import java.util.Iterator;
import java.util.logging.Logger;

public class SignatureVerificationInterceptor extends AbstractSoapInterceptor {
    
    private static final Logger LOG = Logger.getLogger(SignatureVerificationInterceptor.class.getName());
    private KeystoreManager keystoreManager;
    
    public SignatureVerificationInterceptor(KeystoreManager keystoreManager) {
        super(Phase.POST_PROTOCOL);
        this.keystoreManager = keystoreManager;
    }
    
    @Override
    public void handleMessage(SoapMessage message) throws Fault {
        try {
            Document document = (Document) message.getContent(org.w3c.dom.Node.class);
            if (document == null) {
                throw new Fault(new IllegalArgumentException("Unable to get SOAP message document"));
            }
            
            NodeList signatureNodes = document.getElementsByTagNameNS(XMLSignature.XMLNS, "Signature");
            if (signatureNodes.getLength() == 0) {
                throw new Fault(new SecurityException("No signature found in SOAP message"));
            }
            
            Element signatureElement = (Element) signatureNodes.item(0);
            
            XMLSignatureFactory factory = XMLSignatureFactory.getInstance("DOM");
            DOMValidateContext validateContext = new DOMValidateContext(new KeyValueKeySelector(), signatureElement);
            
            XMLSignature signature = factory.unmarshalXMLSignature(validateContext);
            
            boolean isValid = signature.validate(validateContext);
            
            if (!isValid) {
                LOG.severe("Signature validation failed");
                boolean coreValid = signature.getSignatureValue().validate(validateContext);
                LOG.info("Signature core validation status: " + coreValid);
                
                Iterator<?> i = signature.getSignedInfo().getReferences().iterator();
                for (int j = 0; i.hasNext(); j++) {
                    Reference ref = (Reference) i.next();
                    boolean refValid = ref.validate(validateContext);
                    LOG.info("Reference[" + j + "] validity status: " + refValid);
                }
                
                throw new Fault(new SecurityException("Invalid signature"));
            }
            
            LOG.info("Signature validated successfully");
            
        } catch (Exception e) {
            LOG.severe("Error verifying signature: " + e.getMessage());
            throw new Fault(e);
        }
    }
    
    private class KeyValueKeySelector extends KeySelector {
        @Override
        public KeySelectorResult select(KeyInfo keyInfo, Purpose purpose, 
                                       AlgorithmMethod method, XMLCryptoContext context)
                throws KeySelectorException {
            
            if (keyInfo == null) {
                throw new KeySelectorException("Null KeyInfo object");
            }
            
            Iterator<?> ki = keyInfo.getContent().iterator();
            while (ki.hasNext()) {
                XMLStructure info = (XMLStructure) ki.next();
                
                if (info instanceof KeyValue) {
                    PublicKey pk = null;
                    try {
                        pk = ((KeyValue) info).getPublicKey();
                    } catch (KeyException ke) {
                        throw new KeySelectorException(ke);
                    }
                    return new SimpleKeySelectorResult(pk);
                }
                
                if (info instanceof X509Data) {
                    X509Data x509Data = (X509Data) info;
                    Iterator<?> xi = x509Data.getContent().iterator();
                    while (xi.hasNext()) {
                        Object o = xi.next();
                        if (o instanceof X509Certificate) {
                            PublicKey pk = ((X509Certificate) o).getPublicKey();
                            return new SimpleKeySelectorResult(pk);
                        }
                    }
                }
            }
            throw new KeySelectorException("No KeyValue element found");
        }
    }
    
    private static class SimpleKeySelectorResult implements KeySelectorResult {
        private PublicKey pk;
        
        SimpleKeySelectorResult(PublicKey pk) {
            this.pk = pk;
        }
        
        @Override
        public Key getKey() {
            return pk;
        }
    }
}


// KeystoreManager.java
package com.banking.security;

import java.io.FileInputStream;
import java.io.InputStream;
import java.security.*;
import java.security.cert.X509Certificate;

public class KeystoreManager {
    
    private KeyStore keystore;
    private String keystorePassword;
    
    public KeystoreManager(String keystorePath, String keystorePassword) throws Exception {
        this.keystorePassword = keystorePassword;
        this.keystore = KeyStore.getInstance("JKS");
        
        try (InputStream is = new FileInputStream(keystorePath)) {
            keystore.load(is, keystorePassword.toCharArray());
        }
    }
    
    public PrivateKey getPrivateKey(String alias, String keyPassword) throws Exception {
        return (PrivateKey) keystore.getKey(alias, keyPassword.toCharArray());
    }
    
    public X509Certificate getCertificate(String alias) throws Exception {
        return (X509Certificate) keystore.getCertificate(alias);
    }
    
    public PublicKey getPublicKey(String alias) throws Exception {
        X509Certificate cert = getCertificate(alias);
        return cert.getPublicKey();
    }
    
    public KeyStore getKeystore() {
        return keystore;
    }
}


// SOAPMessageParser.java
package com.banking.security;

import org.w3c.dom.*;
import javax.xml.parsers.*;
import javax.xml.xpath.*;
import java.io.ByteArrayInputStream;
import java.util.ArrayList;
import java.util.List;

public class SOAPMessageParser {
    
    private Document document;
    private XPath xpath;
    
    public SOAPMessageParser(String soapMessage) throws Exception {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true);
        DocumentBuilder builder = factory.newDocumentBuilder();
        this.document = builder.parse(new ByteArrayInputStream(soapMessage.getBytes()));
        
        XPathFactory xpathFactory = XPathFactory.newInstance();
        this.xpath = xpathFactory.newXPath();
    }
    
    public SOAPMessageParser(Document document) {
        this.document = document;
        XPathFactory xpathFactory = XPathFactory.newInstance();
        this.xpath = xpathFactory.newXPath();
    }
    
    public Element getSignatureElement() throws Exception {
        NodeList nodes = document.getElementsByTagNameNS("http://www.w3.org/2000/09/xmldsig#", "Signature");
        if (nodes.getLength() > 0) {
            return (Element) nodes.item(0);
        }
        return null;
    }
    
    public List<Element> getSignedElements() throws Exception {
        List<Element> signedElements = new ArrayList<>();
        
        NodeList references = document.getElementsByTagNameNS("http://www.w3.org/2000/09/xmldsig#", "Reference");
        for (int i = 0; i < references.getLength(); i++) {
            Element reference = (Element) references.item(i);
            String uri = reference.getAttribute("URI");
            
            if (uri.startsWith("#")) {
                String id = uri.substring(1);
                Element signedElement = document.getElementById(id);
                if (signedElement != null) {
                    signedElements.add(signedElement);
                }
            }
        }
        
        return signedElements;
    }
    
    public String getBodyContent() throws Exception {
        NodeList bodyNodes = document.getElementsByTagNameNS("http://schemas.xmlsoap.org/soap/envelope/", "Body");
        if (bodyNodes.getLength() > 0) {
            Element body = (Element) bodyNodes.item(0);
            return nodeToString(body);
        }
        return null;
    }
    
    public Element getSecurityHeader() throws Exception {
        NodeList securityNodes = document.getElementsByTagNameNS(
            "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd", 
            "Security"
        );
        if (securityNodes.getLength() > 0) {
            return (Element) securityNodes.item(0);
        }
        return null;
    }
    
    private String nodeToString(Node node) {
        StringBuilder sb = new StringBuilder();
        NodeList children = node.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.TEXT_NODE) {
                sb.append(child.getNodeValue());
            }
        }
        return sb.toString();
    }
    
    public Document getDocument() {
        return document;
    }
}


