            JaxWsServerFactoryBean factory = new JaxWsServerFactoryBean();
            factory.setBus(bus);
            factory.setServiceClass(BankingServiceImpl.class);
            factory.setAddress("http://localhost:8080/banking/services/BankingService");
            
            Map<String, Object> inProps = new HashMap<>();
