            inProps.put(WSHandlerConstants.SIG_PROP_FILE, "server-crypto.properties");
            inProps.put(WSHandlerConstants.SIG_VER_PROP_FILE, "server-crypto.properties");
            inProps.put(WSHandlerConstants.PW_CALLBACK_CLASS, ServerPasswordCallback.class.getName());
            
            WSS4JInInterceptor wss4jIn = new WSS4JInInterceptor(inProps);
            factory.getInInterceptors().add(wss4jIn);
            
